@Component
public class XSSProtection {
    
    public static String sanitizeHtml(String input) {
        if (input == null) return null;
        
        StringBuilder sanitized = new StringBuilder();
        boolean inTag = false;
        boolean inScript = false;
        boolean inStyle = false;
        
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            
            if (c == '<') {
                inTag = true;
                if (i + 6 < input.length() && 
                    input.substring(i, i + 7).equalsIgnoreCase("<script")) {
                    inScript = true;
                } else if (i + 5 < input.length() && 
                    input.substring(i, i + 6).equalsIgnoreCase("<style")) {
                    inStyle = true;
                }
                continue;
            }
            
            if (c == '>') {
                inTag = false;
                if (inScript) inScript = false;
                if (inStyle) inStyle = false;
                continue;
            }
            
            if (!inTag && !inScript && !inStyle) {
                sanitized.append(c);
            }
        }
        
        return sanitized.toString();
    }
}

@Controller
public class CommentController {
    
    @Autowired
    private CommentService commentService;
    
    @GetMapping("/comments")
    public String showComments(Model model) {
        List<Comment> comments = commentService.getAllComments();
        List<Comment> sanitizedComments = comments.stream()
            .map(comment -> {
                Comment sanitized = new Comment();
                sanitized.setId(comment.getId());
                sanitized.setAuthor(comment.getAuthor());
                sanitized.setCreatedAt(comment.getCreatedAt());
                sanitized.setContent(XSSProtection.sanitizeHtml(comment.getContent()));
                return sanitized;
            })
            .collect(Collectors.toList());
        model.addAttribute("comments", sanitizedComments);
        return "comments";
    }
}